#!/usr/bin/env python3

import subprocess
import sys
import hashlib
import json
import os
import argparse
from pathlib import Path
from datetime import datetime
from typing import List, Dict, Set, Optional
import re


class DependencyManager:
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.requirements_file = self.project_root / "requirements.txt"
        self.requirements_dev_file = self.project_root / "requirements-dev.txt"
        self.requirements_lock = self.project_root / "requirements.lock"
        self.pyproject_toml = self.project_root / "pyproject.toml"
        self.poetry_lock = self.project_root / "poetry.lock"
        
    def detect_dependency_tool(self) -> str:
        if self.poetry_lock.exists() or self.pyproject_toml.exists():
            return "poetry"
        elif self.requirements_file.exists():
            return "pip"
        else:
            return "unknown"
    
    def generate_pip_lock_file(self, input_file: Path, output_file: Path, 
                               upgrade: bool = False) -> None:
        print(f"Generating lock file from {input_file} to {output_file}...")
        
        cmd = [
            sys.executable, "-m", "pip", "install", 
            "-r", str(input_file),
            "--dry-run", "--report", "-"
        ]
        
        try:
            result = subprocess.run(cmd, capture_output=True, text=True, check=True)
            report = json.loads(result.stdout)
            
            dependencies = []
            for item in report.get("install", []):
                metadata = item.get("metadata", {})
                name = metadata.get("name")
                version = metadata.get("version")
                
                if name and version:
                    download_info = item.get("download_info", {})
                    url = download_info.get("url", "")
                    
                    hash_value = None
                    if "sha256" in download_info:
                        hash_value = f"sha256:{download_info['sha256']}"
                    
                    dependencies.append({
                        "name": name,
                        "version": version,
                        "url": url,
                        "hash": hash_value
                    })
            
            with open(output_file, "w") as f:
                f.write(f"# Generated on {datetime.now().isoformat()}\n")
                f.write(f"# Source: {input_file}\n")
                f.write("#\n")
                
                for dep in sorted(dependencies, key=lambda x: x["name"].lower()):
                    line = f"{dep['name']}=={dep['version']}"
                    if dep['hash']:
                        line += f" --hash={dep['hash']}"
                    f.write(line + "\n")
            
            print(f"Lock file generated successfully: {output_file}")
            
        except subprocess.CalledProcessError as e:
            print(f"Error generating lock file: {e}")
            print(f"stderr: {e.stderr}")
            sys.exit(1)
        except Exception as e:
            print(f"Error: {e}")
            sys.exit(1)
    
    def generate_pip_compile_lock(self, input_file: Path, output_file: Path,
                                   upgrade: bool = False) -> None:
        print(f"Using pip-tools to compile {input_file}...")
        
        cmd = [
            sys.executable, "-m", "piptools", "compile",
            "--generate-hashes",
            "--output-file", str(output_file),
            str(input_file)
        ]
        
        if upgrade:
            cmd.append("--upgrade")
        
        try:
            subprocess.run(cmd, check=True)
            print(f"Lock file compiled successfully: {output_file}")
        except subprocess.CalledProcessError:
            print("Error: pip-tools not installed. Install with: pip install pip-tools")
            print("Falling back to alternative method...")
            self.generate_pip_lock_file(input_file, output_file, upgrade)
    
    def freeze_current_environment(self, output_file: Path, with_hashes: bool = True) -> None:
        print(f"Freezing current environment to {output_file}...")
        
        cmd = [sys.executable, "-m", "pip", "freeze"]
        
        try:
            result = subprocess.run(cmd, capture_output=True, text=True, check=True)
            packages = result.stdout.strip().split("\n")
            
            with open(output_file, "w") as f:
                f.write(f"# Frozen on {datetime.now().isoformat()}\n")
                f.write("#\n")
                
                for package in sorted(packages):
                    if with_hashes and "==" in package:
                        pkg_name, pkg_version = package.split("==")
                        hash_value = self.get_package_hash(pkg_name, pkg_version)
                        if hash_value:
                            f.write(f"{package} --hash=sha256:{hash_value}\n")
                        else:
                            f.write(f"{package}\n")
                    else:
                        f.write(f"{package}\n")
            
            print(f"Environment frozen successfully: {output_file}")
            
        except subprocess.CalledProcessError as e:
            print(f"Error freezing environment: {e}")
            sys.exit(1)
    
    def get_package_hash(self, package: str, version: str) -> Optional[str]:
        cmd = [
            sys.executable, "-m", "pip", "download",
            f"{package}=={version}",
            "--no-deps", "--dest", "/tmp"
        ]
        
        try:
            result = subprocess.run(cmd, capture_output=True, text=True)
            output = result.stderr + result.stdout
            
            hash_match = re.search(r'sha256:([a-f0-9]{64})', output)
            if hash_match:
                return hash_match.group(1)
            
            for line in output.split("\n"):
                if "Saved" in line and package in line:
                    filepath_match = re.search(r'/tmp/([^\s]+)', line)
                    if filepath_match:
                        filepath = f"/tmp/{filepath_match.group(1)}"
                        if os.path.exists(filepath):
                            return self.calculate_file_hash(filepath)
            
            return None
        except Exception:
            return None
    
    def calculate_file_hash(self, filepath: str) -> str:
        sha256_hash = hashlib.sha256()
        with open(filepath, "rb") as f:
            for byte_block in iter(lambda: f.read(4096), b""):
                sha256_hash.update(byte_block)
        return sha256_hash.hexdigest()
    
    def poetry_lock_update(self, package: Optional[str] = None) -> None:
        print("Updating Poetry lock file...")
        
        cmd = ["poetry", "lock"]
        
        if package:
            cmd.extend(["--no-update"])
        
        try:
            subprocess.run(cmd, check=True, cwd=self.project_root)
            print("Poetry lock file updated successfully")
        except subprocess.CalledProcessError as e:
            print(f"Error updating Poetry lock: {e}")
            sys.exit(1)
    
    def poetry_install(self, dev: bool = True) -> None:
        print("Installing dependencies from Poetry lock file...")
        
        cmd = ["poetry", "install"]
        
        if not dev:
            cmd.append("--no-dev")
        
        try:
            subprocess.run(cmd, check=True, cwd=self.project_root)
            print("Dependencies installed successfully")
        except subprocess.CalledProcessError as e:
            print(f"Error installing dependencies: {e}")
            sys.exit(1)
    
    def poetry_export(self, output_file: Path, dev: bool = False, 
                     with_hashes: bool = True) -> None:
        print(f"Exporting Poetry lock to {output_file}...")
        
        cmd = ["poetry", "export", "-f", "requirements.txt", "-o", str(output_file)]
        
        if dev:
            cmd.append("--dev")
        
        if with_hashes:
            cmd.append("--with-hashes")
        
        try:
            subprocess.run(cmd, check=True, cwd=self.project_root)
            print(f"Exported successfully to {output_file}")
        except subprocess.CalledProcessError as e:
            print(f"Error exporting Poetry lock: {e}")
            sys.exit(1)
    
    def verify_lock_file(self, lock_file: Path) -> bool:
        print(f"Verifying lock file: {lock_file}...")
        
        if not lock_file.exists():
            print(f"Lock file does not exist: {lock_file}")
            return False
        
        with open(lock_file, "r") as f:
            lines = f.readlines()
        
        has_versions = False
        has_hashes = False
        
        for line in lines:
            line = line.strip()
            if line and not line.startswith("#"):
                if "==" in line:
                    has_versions = True
                if "--hash=" in line:
                    has_hashes = True
        
        if has_versions:
            print("✓ Lock file has pinned versions")
        else:
            print("✗ Lock file missing pinned versions")
        
        if has_hashes:
            print("✓ Lock file has integrity hashes")
        else:
            print("⚠ Lock file missing integrity hashes (recommended)")
        
        return has_versions
    
    def sync_dependencies(self, lock_file: Path) -> None:
        print(f"Installing dependencies from {lock_file}...")
        
        cmd = [
            sys.executable, "-m", "pip", "install",
            "-r", str(lock_file),
            "--require-hashes" if "--hash=" in lock_file.read_text() else ""
        ]
        
        cmd = [c for c in cmd if c]
        
        try:
            subprocess.run(cmd, check=True)
            print("Dependencies installed successfully")
        except subprocess.CalledProcessError as e:
            print(f"Error installing dependencies: {e}")
            sys.exit(1)
    
    def check_outdated(self, format: str = "columns") -> None:
        print("Checking for outdated packages...\n")
        
        tool = self.detect_dependency_tool()
        
        if tool == "poetry":
            cmd = ["poetry", "show", "--outdated"]
            try:
                subprocess.run(cmd, check=True, cwd=self.project_root)
            except subprocess.CalledProcessError:
                print("No outdated packages or Poetry not available")
        else:
            cmd = [sys.executable, "-m", "pip", "list", "--outdated", f"--format={format}"]
            try:
                subprocess.run(cmd, check=True)
            except subprocess.CalledProcessError:
                print("No outdated packages")
    
    def diff_lock_files(self, old_lock: Path, new_lock: Path) -> None:
        print(f"Comparing {old_lock} with {new_lock}...\n")
        
        def parse_lock_file(filepath: Path) -> Dict[str, str]:
            packages = {}
            with open(filepath, "r") as f:
                for line in f:
                    line = line.strip()
                    if line and not line.startswith("#"):
                        match = re.match(r'([a-zA-Z0-9_-]+)==([0-9.]+)', line)
                        if match:
                            packages[match.group(1).lower()] = match.group(2)
            return packages
        
        old_packages = parse_lock_file(old_lock)
        new_packages = parse_lock_file(new_lock)
        
        added = set(new_packages.keys()) - set(old_packages.keys())
        removed = set(old_packages.keys()) - set(new_packages.keys())
        common = set(old_packages.keys()) & set(new_packages.keys())
        
        changed = {
            pkg for pkg in common 
            if old_packages[pkg] != new_packages[pkg]
        }
        
        if added:
            print("Added packages:")
            for pkg in sorted(added):
                print(f"  + {pkg}=={new_packages[pkg]}")
            print()
        
        if removed:
            print("Removed packages:")
            for pkg in sorted(removed):
                print(f"  - {pkg}=={old_packages[pkg]}")
            print()
        
        if changed:
            print("Updated packages:")
            for pkg in sorted(changed):
                print(f"  {pkg}: {old_packages[pkg]} -> {new_packages[pkg]}")
            print()
        
        if not (added or removed or changed):
            print("No differences found")
    
    def create_requirements_from_imports(self, source_dir: Path, output_file: Path) -> None:
        print(f"Analyzing imports in {source_dir}...")
        
        imports = set()
        
        for python_file in source_dir.rglob("*.py"):
            with open(python_file, "r") as f:
                content = f.read()
                
                import_matches = re.finditer(r'^import\s+([a-zA-Z0-9_]+)', content, re.MULTILINE)
                for match in import_matches:
                    imports.add(match.group(1))
                
                from_matches = re.finditer(r'^from\s+([a-zA-Z0-9_]+)', content, re.MULTILINE)
                for match in from_matches:
                    imports.add(match.group(1))
        
        stdlib_modules = set(sys.stdlib_module_names)
        third_party = imports - stdlib_modules
        
        with open(output_file, "w") as f:
            f.write(f"# Generated from imports in {source_dir}\n")
            f.write(f"# Date: {datetime.now().isoformat()}\n")
            f.write("#\n")
            for module in sorted(third_party):
                f.write(f"{module}\n")
        
        print(f"Found {len(third_party)} third-party imports")
        print(f"Requirements template written to {output_file}")


def main():
    parser = argparse.ArgumentParser(
        description="Python Dependency Management Tool",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  # Generate lock file from requirements.txt
  %(prog)s lock requirements.txt requirements.lock
  
  # Freeze current environment with hashes
  %(prog)s freeze requirements.lock --hashes
  
  # Update Poetry lock file
  %(prog)s poetry-lock
  
  # Export Poetry dependencies to requirements.txt
  %(prog)s poetry-export requirements.txt --hashes
  
  # Verify lock file integrity
  %(prog)s verify requirements.lock
  
  # Check for outdated packages
  %(prog)s outdated
  
  # Compare two lock files
  %(prog)s diff old.lock new.lock
  
  # Sync dependencies from lock file
  %(prog)s sync requirements.lock
        """
    )
    
    parser.add_argument("--project-root", default=".", help="Project root directory")
    
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")
    
    lock_parser = subparsers.add_parser("lock", help="Generate lock file from requirements")
    lock_parser.add_argument("input", type=Path, help="Input requirements file")
    lock_parser.add_argument("output", type=Path, help="Output lock file")
    lock_parser.add_argument("--upgrade", action="store_true", help="Upgrade packages")
    lock_parser.add_argument("--use-pip-tools", action="store_true", help="Use pip-tools")
    
    freeze_parser = subparsers.add_parser("freeze", help="Freeze current environment")
    freeze_parser.add_argument("output", type=Path, help="Output file")
    freeze_parser.add_argument("--hashes", action="store_true", help="Include hashes")
    
    poetry_lock_parser = subparsers.add_parser("poetry-lock", help="Update Poetry lock file")
    poetry_lock_parser.add_argument("--package", help="Specific package to update")
    
    poetry_install_parser = subparsers.add_parser("poetry-install", help="Install from Poetry lock")
    poetry_install_parser.add_argument("--no-dev", action="store_true", help="Skip dev dependencies")
    
    poetry_export_parser = subparsers.add_parser("poetry-export", help="Export Poetry lock")
    poetry_export_parser.add_argument("output", type=Path, help="Output file")
    poetry_export_parser.add_argument("--dev", action="store_true", help="Include dev dependencies")
    poetry_export_parser.add_argument("--hashes", action="store_true", help="Include hashes")
    
    verify_parser = subparsers.add_parser("verify", help="Verify lock file")
    verify_parser.add_argument("lockfile", type=Path, help="Lock file to verify")
    
    sync_parser = subparsers.add_parser("sync", help="Sync dependencies from lock file")
    sync_parser.add_argument("lockfile", type=Path, help="Lock file to sync from")
    
    outdated_parser = subparsers.add_parser("outdated", help="Check for outdated packages")
    outdated_parser.add_argument("--format", default="columns", choices=["columns", "json", "freeze"])
    
    diff_parser = subparsers.add_parser("diff", help="Compare two lock files")
    diff_parser.add_argument("old", type=Path, help="Old lock file")
    diff_parser.add_argument("new", type=Path, help="New lock file")
    
    analyze_parser = subparsers.add_parser("analyze", help="Analyze imports in source code")
    analyze_parser.add_argument("source_dir", type=Path, help="Source directory to analyze")
    analyze_parser.add_argument("output", type=Path, help="Output requirements file")
    
    detect_parser = subparsers.add_parser("detect", help="Detect dependency tool")
    
    args = parser.parse_args()
    
    dm = DependencyManager(args.project_root)
    
    if args.command == "lock":
        if args.use_pip_tools:
            dm.generate_pip_compile_lock(args.input, args.output, args.upgrade)
        else:
            dm.generate_pip_lock_file(args.input, args.output, args.upgrade)
    
    elif args.command == "freeze":
        dm.freeze_current_environment(args.output, args.hashes)
    
    elif args.command == "poetry-lock":
        dm.poetry_lock_update(args.package)
    
    elif args.command == "poetry-install":
        dm.poetry_install(not args.no_dev)
    
    elif args.command == "poetry-export":
        dm.poetry_export(args.output, args.dev, args.hashes)
    
    elif args.command == "verify":
        dm.verify_lock_file(args.lockfile)
    
    elif args.command == "sync":
        dm.sync_dependencies(args.lockfile)
    
    elif args.command == "outdated":
        dm.check_outdated(args.format)
    
    elif args.command == "diff":
        dm.diff_lock_files(args.old, args.new)
    
    elif args.command == "analyze":
        dm.create_requirements_from_imports(args.source_dir, args.output)
    
    elif args.command == "detect":
        tool = dm.detect_dependency_tool()
        print(f"Detected dependency tool: {tool}")
    
    else:
        parser.print_help()


if __name__ == "__main__":
    main()